INSERT INTO posts (id, user_id, judul, deskripsi, file_path, created_at, updated_at, is_hidden) VALUES
(1, 2, 'Bagaimana cara membaca tabel statistik BPS Provinsi Lampung?', 'Saya baru pertama kali mengakses data dari website BPS Lampung. Ada banyak tabel dengan angka-angka yang saya kurang pahami. Apakah ada panduan cara membaca dan menginterpretasikan tabel statistik tersebut? Khususnya tabel yang berisi data penduduk per kabupaten.', NULL, '2026-02-15 21:58:49', '2026-02-15 21:58:49', FALSE),
(2, 3, 'Apa perbedaan antara Sensus Penduduk dan Survei Penduduk Antar Sensus (SUPAS)?', 'Saya sering mendengar dua istilah ini dalam konteks data kependudukan Indonesia. Bisa dijelaskan apa perbedaan mendasarnya? Kapan masing-masing dilaksanakan dan apa tujuan utamanya?', NULL, '2026-02-17 21:58:49', '2026-02-17 21:58:49', FALSE),
(3, 4, 'Berapa jumlah penduduk Provinsi Lampung berdasarkan data terbaru BPS?', 'Saya membutuhkan data jumlah penduduk Provinsi Lampung terbaru untuk keperluan penelitian skripsi. Mohon informasinya beserta sumber dan tahun datanya. Apakah bisa dirinci per kabupaten/kota?', NULL, '2026-02-20 21:58:49', '2026-02-20 21:58:49', FALSE),
(4, 5, 'Apa yang dimaksud dengan PDRB dan bagaimana cara menghitungnya?', 'Dalam laporan ekonomi daerah sering disebut istilah PDRB. Saya ingin memahami apa pengertiannya, apa bedanya dengan PDB nasional, dan bagaimana BPS menghitung angka ini?', NULL, '2026-02-22 21:58:49', '2026-02-22 21:58:49', FALSE),
(5, 6, 'Bagaimana cara mengunduh data mikro dari website BPS?', 'Saya perlu data mikro untuk keperluan analisis statistik lanjutan. Apakah BPS menyediakan data mikro yang bisa diunduh publik? Bagaimana prosedur mendapatkannya dan apa saja formatnya?', NULL, '2026-02-24 21:58:49', '2026-02-24 21:58:49', FALSE),
(6, 7, 'Apa indikator yang digunakan BPS untuk mengukur tingkat kemiskinan?', 'Saya membaca berita tentang penurunan angka kemiskinan di Lampung. Indikator apa saja yang BPS gunakan untuk mengukur kemiskinan? Apakah hanya berdasarkan pendapatan saja atau ada faktor lain?', NULL, '2026-02-26 21:58:49', '2026-02-26 21:58:49', FALSE),
(7, 8, 'Bagaimana cara menginterpretasikan angka inflasi bulanan dari BPS?', 'BPS setiap bulan merilis data inflasi. Saya ingin memahami cara membaca rilis tersebut. Apa itu inflasi month to month, year on year, dan calendar year? Apa bedanya?', NULL, '2026-02-28 21:58:49', '2026-02-28 21:58:49', FALSE),
(8, 9, 'Apakah data BPS bisa digunakan untuk penelitian akademik?', 'Saya mahasiswa yang sedang mengerjakan tugas akhir. Apakah data yang dipublikasikan BPS boleh digunakan untuk penelitian akademik? Bagaimana cara mencantumkan sumbernya dalam daftar pustaka?', NULL, '2026-03-02 21:58:49', '2026-03-02 21:58:49', FALSE),
(9, 10, 'Apa perbedaan antara angka absolut dan relatif dalam laporan statistik?', 'Ketika membaca laporan BPS, kadang data disajikan dalam bentuk angka absolut seperti jumlah jiwa, kadang relatif seperti persentase. Kapan sebaiknya menggunakan masing-masing?', NULL, '2026-03-04 21:58:49', '2026-03-04 21:58:49', FALSE),
(10, 2, 'Bagaimana tren angka pengangguran di Lampung beberapa tahun terakhir?', 'Saya ingin mengetahui tren Tingkat Pengangguran Terbuka (TPT) di Provinsi Lampung dalam 5 tahun terakhir. Ada data yang tersedia dan bagaimana perbandingannya dengan rata-rata nasional?', NULL, '2026-03-06 21:58:49', '2026-03-06 21:58:49', FALSE),
(11, 3, 'Apa itu Indeks Pembangunan Manusia (IPM) dan komponen apa yang mempengaruhinya?', 'Saya sering melihat angka IPM dalam laporan pembangunan daerah. Ingin memahami: apa itu IPM, bagaimana cara menghitungnya, dan apa saja dimensi yang diukur menurut metodologi BPS?', NULL, '2026-03-08 21:58:49', '2026-03-08 21:58:49', FALSE),
(12, 4, 'Bagaimana cara akses data Sakernas (Survei Angkatan Kerja Nasional)?', 'Untuk penelitian ketenagakerjaan, saya membutuhkan data dari Sakernas. Bagaimana cara mengaksesnya? Apakah perlu registrasi khusus? Data tahun berapa saja yang tersedia?', NULL, '2026-03-10 21:58:49', '2026-03-10 21:58:49', FALSE),
(13, 5, 'Apa perbedaan antara data primer dan data sekunder dalam statistik?', 'Dalam metodologi penelitian sering disebut data primer dan sekunder. Dalam konteks statistik BPS, data mana yang termasuk primer dan mana yang sekunder?', NULL, '2026-03-12 21:58:49', '2026-03-12 21:58:49', FALSE),
(14, 6, 'Bagaimana cara membandingkan data statistik antar provinsi di Indonesia?', 'Saya ingin membandingkan berbagai indikator statistik Lampung dengan provinsi lain di Sumatera. Apakah ada platform dari BPS yang memudahkan perbandingan data antar provinsi?', NULL, '2026-03-14 21:58:49', '2026-03-14 21:58:49', FALSE),
(15, 7, 'Apa itu Nilai Tukar Petani (NTP) dan mengapa penting bagi sektor pertanian?', 'Lampung adalah provinsi agraris. Saya ingin memahami indikator NTP yang sering muncul dalam laporan BPS. Apa pengertiannya dan apa artinya bila NTP di bawah 100?', NULL, '2026-03-16 21:58:49', '2026-03-16 21:58:49', FALSE),
