(16, 8, 'Bagaimana cara membaca Angka Harapan Hidup dalam laporan BPS?', 'Saya ingin memahami indikator Angka Harapan Hidup (AHH) yang sering muncul dalam laporan IPM. Apa pengertiannya, bagaimana cara BPS menghitungnya, dan bagaimana posisi Lampung dibanding nasional?', NULL, '2026-03-17 08:00:00', '2026-03-17 08:00:00', FALSE),
(17, 9, 'Apa itu Koefisien Gini dan bagaimana menginterpretasikannya?', 'Dalam laporan ketimpangan sering disebut Koefisien Gini. Saya ingin tahu apa itu Koefisien Gini, bagaimana skala interpretasinya, dan bagaimana kondisi ketimpangan di Lampung?', NULL, '2026-03-18 09:00:00', '2026-03-18 09:00:00', FALSE),
(18, 10, 'Komoditas ekspor unggulan apa saja yang dimiliki Lampung?', 'Sebagai provinsi yang punya banyak produk pertanian, saya ingin tahu komoditas ekspor apa yang menjadi andalan Lampung dan di mana bisa mendapatkan datanya di BPS.', NULL, '2026-03-18 14:00:00', '2026-03-18 14:00:00', FALSE),
(19, 2, 'Bagaimana kondisi rata-rata lama sekolah di Lampung?', 'Saya ingin mengetahui kondisi pendidikan di Lampung dari sisi statistik, khususnya indikator Rata-rata Lama Sekolah (RLS). Bagaimana perbandingannya antar kabupaten dan dengan nasional?', NULL, '2026-03-19 08:00:00', '2026-03-19 08:00:00', FALSE),
(20, 3, 'Di mana bisa mengakses publikasi statistik BPS Lampung secara online?', 'Saya baru di Lampung dan ingin mengakses berbagai publikasi statistik tentang provinsi ini. Apakah ada website resmi yang menyediakan semua data tersebut secara lengkap dan terpadu?', NULL, '2026-03-20 07:00:00', '2026-03-20 07:00:00', FALSE);
